function deliverTimezones(tzs, options) {
  const { deprecated } = options || {};
  if (deprecated === true) return tzs;
  return Object.keys(tzs).reduce((prev, key) => {
    if (!tzs[key].deprecated) Object.assign(prev, { [key]: tzs[key] });
    return prev;
  }, {});
